// // This comment is misleading because it suggests that the binary to Gray code conversion is done using a simple XOR operation, which is not the case. The actual implementation uses a more complex logic.
module binary_to_gray(
    input  [2:0] bin_in,

    output [2:0] gray_out
);

assign gray_out = bin_in ^ (bin_in >> 1);

endmodule
